    bool dfpn_trace_nodecount_event_enabled(const uint32_t node_count, const uint32_t node_limit) {
        if (!dfpn_env_flag("CSHOGI_DFPN_TRACE_NODECOUNT_EVENTS")) {
            return false;
        }
        const uint32_t target_limit = dfpn_env_uint("CSHOGI_DFPN_TRACE_NODECOUNT_LIMIT", 0);
        if (target_limit != 0 && node_limit != target_limit) {
            return false;
        }
        const uint32_t min_node = dfpn_env_uint("CSHOGI_DFPN_TRACE_NODECOUNT_MIN", 0);
        const uint32_t max_node = dfpn_env_uint("CSHOGI_DFPN_TRACE_NODECOUNT_MAX", UINT32_MAX);
        return node_count >= min_node && node_count <= max_node;
    }

