        out += ' ';
        out += std::bitset<8>(info.liberty_candidate).to_string();
        out += ' ';
        out += std::bitset<8>(info.liberty).to_string();
        out += ' ';
        out += std::bitset<8>(info.drop_candidate).to_string();
