    inline bool dfpn_trace_enabled() {
#if !CSHOGI_ENABLE_DFPN_TRACE_CODE
        return false;
#else
#ifdef NDEBUG
        return false;
#else
        static const bool enabled = []() {
            char* value = nullptr;
            size_t value_len = 0;
            const errno_t env_err = _dupenv_s(&value, &value_len, "CSHOGI_DFPN_DEBUG");
            const bool result = env_err == 0 && value != nullptr && value_len > 0;
            free(value);
            return result;
        }();
        return enabled;
#endif
#endif
    }

    uint64_t osl_system_memory_use_limit() {
#ifdef _WIN32
        MEMORYSTATUSEX statex{};
        statex.dwLength = sizeof(statex);
        if (GlobalMemoryStatusEx(&statex)) {
            return static_cast<uint64_t>(statex.ullTotalPhys);
        }
        return 0;
#else
        std::ifstream is("/proc/meminfo");
        std::string name;
        uint64_t value = 0;
        std::string unit;
        if (is >> name >> value >> unit && name == "MemTotal:" && unit == "kB") {
            return value * 1024ull;
        }
        return 0;
#endif
    }

    uint64_t osl_resident_memory_use() {
#ifdef _WIN32
        PROCESS_MEMORY_COUNTERS pmc{};
        if (GetProcessMemoryInfo(GetCurrentProcess(), &pmc, sizeof(pmc))) {
            return static_cast<uint64_t>(pmc.WorkingSetSize);
        }
        return 0;
#else
        std::ifstream is("/proc/self/statm");
        uint64_t total = 0;
        uint64_t resident = 0;
        if (is >> total >> resident) {
            return resident * 4096ull;
        }
        return 0;
#endif
    }

    double osl_memory_use_ratio() {
        static const uint64_t memory_limit = osl_system_memory_use_limit();
        if (memory_limit == 0) {
            return 0.0;
        }
        return static_cast<double>(osl_resident_memory_use()) / static_cast<double>(memory_limit);
    }

