    inline bool trace_zukou001_target_store_position_release(const Position& pos) {
        if (!dfpn_release_trace_zukou_target_store_enabled()) {
            return false;
        }
        const Key key = board_index_key(pos);
        if (key != static_cast<Key>(8355107728863084742ull)
            && key != static_cast<Key>(9245589005554448721ull)
            && key != static_cast<Key>(18419469664757526953ull)
            && key != static_cast<Key>(7729162959417273696ull)
            && key != static_cast<Key>(2590034863942613529ull)
            && key != static_cast<Key>(9263723947484102751ull)) {
            return false;
        }
        const std::string sfen = pos.toSFEN();
        return sfen == "2G6/1p+P6/pk7/n2sS4/1b2lR3/+B1lNl4/1N1p5/1S7/8K b SPr3gnl13p 47"
            || sfen == "2G6/1p+P6/pk3R3/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w SPr3gnl13p 48"
            || sfen == "2G6/1p+P6/pk3+R3/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w SPr3gnl13p 48"
            || sfen == "2G6/1p+P6/pkp2R3/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K b SPr3gnl12p 49"
            || sfen == "2G6/1p+P6/pk+R6/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w S2Pr3gnl12p 50"
            || sfen == "2G6/1p7/pk+P6/n3S4/1b2l4/+B1lNl4/1N1p5/1S7/8K w 2S2P2r3gnl12p 52";
    }

