    struct ImmediateMateOrderContext {
        Color attack_color = Black;
        Square target_king = SquareNum;
        int move_candidate_mask = 0;
        uint8_t drop_candidate_mask = 0;
    };

    int immediate_mate_dir_index(const Move move, const ImmediateMateOrderContext& ctx) {
        const int file_delta = static_cast<int>(makeFile(ctx.target_king)) - static_cast<int>(makeFile(move.to()));
        const int rank_delta = static_cast<int>(makeRank(ctx.target_king)) - static_cast<int>(makeRank(move.to()));
        if ((file_delta == 0 && rank_delta == 0)
            || std::abs(file_delta) > 1
            || std::abs(rank_delta) > 1) {
            return -1;
        }
        return dir_index_from_delta(
            ctx.attack_color,
            file_delta == 0 ? 0 : (file_delta > 0 ? 1 : -1),
            rank_delta == 0 ? 0 : (rank_delta > 0 ? 1 : -1));
    }

    uint32_t immediate_mate_order_key(const Move move, const ImmediateMateOrderContext& ctx) {
        const int dir_index = immediate_mate_dir_index(move, ctx);
        const uint32_t dir_key = dir_index >= 0 ? static_cast<uint32_t>(dir_index) : 0xffu;

        if (!move.isDrop() && move.pieceTypeFrom() != Knight) {
            if (dir_index >= 0 && (ctx.move_candidate_mask & (1 << dir_index)) != 0) {
                return dir_key;
            }
            return 0x100u + dir_key;
        }

        if (!move.isDrop()) {
            return 0x200u + dir_key;
        }

        const auto osl_drop_piece_key = [](const PieceType piece_type) -> uint32_t {
            switch (piece_type) {
            case Gold: return 1;
            case Pawn: return 2;
            case Lance: return 3;
            case Knight: return 4;
            case Silver: return 5;
            case Bishop: return 6;
            case Rook: return 7;
            default: return 0xff;
            }
        };
        const uint32_t piece_key = osl_drop_piece_key(move.pieceTypeDropped());
        if (dir_index >= 0 && (ctx.drop_candidate_mask & (1u << dir_index)) != 0) {
            return 0x300u + (piece_key << 4) + dir_key;
        }
        return 0x400u + (piece_key << 4) + dir_key;
    }

    int osl_king_escape_order_key(const Color defense_color, const Square from, const Move move) {
        if (move.isDrop() || move.pieceTypeFrom() != King) {
            return INT_MAX;
        }

        const int file_delta = static_cast<int>(makeFile(move.to())) - static_cast<int>(makeFile(from));
        const int rank_delta = static_cast<int>(makeRank(move.to())) - static_cast<int>(makeRank(from));
        static constexpr std::array<std::pair<int, int>, 8> kBlackOrder = { {
            { 1, -1 }, { -1, 1 }, { 0, -1 }, { 0, 1 },
            { -1, -1 }, { 1, 1 }, { 1, 0 }, { -1, 0 }
        } };
        static constexpr std::array<std::pair<int, int>, 8> kWhiteOrder = { {
            { 1, -1 }, { -1, 1 }, { 0, 1 }, { 0, -1 },
            { 1, 1 }, { -1, -1 }, { -1, 0 }, { 1, 0 }
        } };
        const auto& order = defense_color == Black ? kBlackOrder : kWhiteOrder;
        for (size_t i = 0; i < order.size(); ++i) {
            if (order[i].first == file_delta && order[i].second == rank_delta) {
                return static_cast<int>(i);
            }
        }
        return INT_MAX;
    }

    bool is_blockable_single_check(const Position& pos, const Square checker, const Square defense_king) {
        const PieceType checker_type = pieceToPieceType(pos.piece(checker));
        const Direction relation = squareRelation(checker, defense_king);
        const int distance = squareDistance(checker, defense_king);
        if (distance <= 1) {
            return false;
        }

        switch (checker_type) {
        case Bishop:
        case Horse:
            return relation == DirecDiagNESW || relation == DirecDiagNWSE;
        case Rook:
        case Dragon:
            return relation == DirecFile || relation == DirecRank;
        case Lance:
            return relation == DirecFile;
        default:
            return false;
        }
    }

    ProofDisproof fixed_escape_by_move_zero(Position& pos, const Color attack_color, Move* best_move = nullptr,
        Hand* proof_pieces = nullptr, const bool no_proof_pieces_attack_estimation = false,
        const bool may_unsafe = true, const OslPieceNumberState* current_piece_numbers = nullptr) {
        if (best_move) {
            *best_move = Move::moveNone();
        }
        if (proof_pieces) {
            *proof_pieces = zero_hand();
        }

        const bool trace_enabled = dfpn_trace_enabled();
        const std::string trace_sfen = trace_enabled ? pos.toSFEN() : std::string();
        const bool trace_issue56_fixed0 = trace_enabled
            && trace_sfen == "5k2l/1R5gr/3+S+B2p1/p2nlpp1p/5ns2/2+BPl3P/1PNK1PP2/1GGS2S2/5G1NL b 5P3p 7";
        const bool trace_fixed_a3_leaf = g_trace_fixed_a3_window
            && dfpn_observe_env_flag("CSHOGI_DFPN_ZUKOU_FIXED_A3_DEFENSE");
        const Square target_king = pos.kingSquare(oppositeColor(attack_color));
        const bool still_checking = target_king && effect_has_at(pos, attack_color, target_king);
        if (trace_fixed_a3_leaf) {
            std::fprintf(stderr,
                "cshogi fixed-a3 leaf enter still_checking=%d in_check=%d may_unsafe=%d no_est=%d sfen=%s\n",
                still_checking ? 1 : 0,
                pos.inCheck() ? 1 : 0,
                may_unsafe ? 1 : 0,
                no_proof_pieces_attack_estimation ? 1 : 0,
                pos.toSFEN().c_str());
        }
        if (trace_issue56_fixed0) {
            std::fprintf(stderr, "cshogi fixed0 enter sfen=%s still_checking=%d\n", trace_sfen.c_str(), still_checking ? 1 : 0);
        }
        if (may_unsafe && still_checking) {
            return ProofDisproof::NoEscape();
        }
        if (!pos.inCheck()) {
            DfpnProfileScope immediate_profile(DfpnProfileSlot::FixedImmediate);
            const Move mate1 = immediate_mate_move_in_1_osl(pos, current_piece_numbers);
            if (trace_fixed_a3_leaf) {
                std::fprintf(stderr,
                    "cshogi fixed-a3 leaf mate1=%s sfen=%s\n",
                    mate1 ? mate1.toUSI().c_str() : "-",
                    pos.toSFEN().c_str());
            }
            if (trace_issue56_fixed0) {
                std::fprintf(stderr, "cshogi fixed0 mate1=%s sfen=%s\n", mate1 ? mate1.toUSI().c_str() : "-", trace_sfen.c_str());
            }
            if (mate1) {
                if (best_move) {
                    *best_move = mate1;
                }
                if (proof_pieces) {
                    *proof_pieces = fixed_attack_leaf_proof_pieces(mate1);
                }
                return ProofDisproof::Checkmate();
            }
        }

        const ProofDisproof result = no_proof_pieces_attack_estimation
            ? ProofDisproof::Unknown()
            : [&]() {
                DfpnProfileScope estimate_profile(DfpnProfileSlot::FixedEscapeLeaf);
                return fixed_attack_estimation_zero(pos, attack_color);
            }();
        if (trace_fixed_a3_leaf) {
            std::fprintf(stderr,
                "cshogi fixed-a3 leaf estimate=%u,%u sfen=%s\n",
                result.proof,
                result.disproof,
                pos.toSFEN().c_str());
        }
        if (trace_issue56_fixed0) {
            std::fprintf(stderr, "cshogi fixed0 estimate=%u,%u sfen=%s\n", result.proof, result.disproof, trace_sfen.c_str());
        }
        return result;
    }

    ProofDisproof fixed_has_escape_by_move_zero(Position& pos, const Color attack_color, Move* best_move = nullptr,
        Hand* proof_pieces = nullptr, const Move last_attack_move = Move::moveNone(),
        const bool no_proof_pieces_attack_estimation = false, const bool may_unsafe_attack = true,
        const OslPieceNumberState* current_piece_numbers = nullptr) {
        if (best_move) {
            *best_move = Move::moveNone();
        }
        if (proof_pieces) {
            *proof_pieces = zero_hand();
        }

        const Color defense_color = oppositeColor(attack_color);
#if CSHOGI_ENABLE_DFPN_TRACE_CODE
        const bool trace_fixed_probe = trace_issue56_fixed_probe_position(pos);
#else
        constexpr bool trace_fixed_probe = false;
#endif
        const Square attacker_king = pos.kingSquare(attack_color);
        if (attacker_king && effect_has_at(pos, defense_color, attacker_king)) {
            return ProofDisproof::NoCheckmate();
        }

        std::array<ExtMove, kMoveBufferSize> buffer;
        ExtMove* last = generateOslmateEscapeNonblockMoves(buffer.data(), pos, false);
        FixedMoveVector<kCheckOrEscapeMoveCapacity> moves;
        FixedMoveVector<kCheckOrEscapeMoveCapacity> king_moves;
        FixedMoveVector<kCheckOrEscapeMoveCapacity> raw_blocking_moves;
        bool raw_blocking_collected = false;

        const Square defense_king = pos.kingSquare(defense_color);
        Bitboard checkers = pos.checkersBB();
        const int checker_count = checkers.popCount();
        int num_captures = 0;
        bool blockable_check = false;
        int nonblock_moves = 0;

        if (checker_count != 1) {
            for (ExtMove* it = buffer.data(); it != last; ++it) {
                const Move move = it->move;
                if (!move.isDrop() && move.pieceTypeFrom() == King) {
                    king_moves.push_back(move);
                }
            }
        }
        else {
            const Square checker = checkers.firstOneFromSQ11();
            blockable_check = !is_unblockable_check(pos);
            for (ExtMove* it = buffer.data(); it != last; ++it) {
                const Move move = it->move;
                const bool is_king_move = !move.isDrop() && move.pieceTypeFrom() == King;
                if (is_king_move) {
                    king_moves.push_back(move);
                }
                else if (move.to() == checker) {
                    moves.push_back(move);
                    ++num_captures;
                }
            }
        }

        // OSL FixedDepthSearcher::defense uses the raw Escape<KING> order.
        // The DFPN main defense move order is sorted elsewhere, but CHECKMATE_D2
        // must keep the fixed-depth generator order because it can change the
        // first nonzero proof aggregate.
        for (const Move move : king_moves) {
            moves.push_back(move);
        }
        reorder_osl_numbered_escape_target_moves_impl(current_piece_numbers, moves);
        nonblock_moves = static_cast<int>(moves.size());

        const auto collect_raw_blocking_moves = [&]() {
            if (raw_blocking_collected) {
                return;
            }
            raw_blocking_collected = true;
            std::array<ExtMove, kMoveBufferSize> full_buffer;
            ExtMove* full_last = generateOslmateEscapeMoves(full_buffer.data(), pos, false, false);
            for (ExtMove* it = full_buffer.data(); it != full_last; ++it) {
                const Move move = it->move;
                const bool is_king_move = !move.isDrop() && move.pieceTypeFrom() == King;
                if (is_king_move || move.to() == checkers.firstOneFromSQ11()) {
                    continue;
                }
                raw_blocking_moves.push_back(move);
            }
            reorder_osl_numbered_escape_target_moves_impl(current_piece_numbers, raw_blocking_moves);
        };

        if (moves.empty()) {
            collect_raw_blocking_moves();
            for (const Move move : raw_blocking_moves) {
                if (move.isDrop()) {
                    if (!effect_has_at(pos, defense_color, move.to())) {
                        continue;
                    }
                }
                else if (std::abs(static_cast<int>(makeFile(move.from())) - static_cast<int>(makeFile(defense_king))) > 1
                    || std::abs(static_cast<int>(makeRank(move.from())) - static_cast<int>(makeRank(defense_king))) > 1) {
                    if (!has_multiple_effect_at(pos, defense_color, move.to())) {
                        continue;
                    }
                }
                moves.push_back(move);
            }
        }

        if (trace_fixed_probe) {
            std::fprintf(stderr, "cshogi issue56 d2 enter sfen=%s nonblock=%zu block=%zu blockable=%d captures=%d\n",
                pos.toSFEN().c_str(),
                moves.size(),
                raw_blocking_moves.size(),
                blockable_check ? 1 : 0,
                num_captures);
            std::fprintf(stderr, "cshogi issue56 d2 nonblock");
            for (const Move move : moves) {
                std::fprintf(stderr, " %s", move.toUSI().c_str());
            }
            std::fprintf(stderr, "\n");
            if (!raw_blocking_moves.empty()) {
                std::fprintf(stderr, "cshogi issue56 d2 blocking");
                for (const Move move : raw_blocking_moves) {
                    std::fprintf(stderr, " %s", move.toUSI().c_str());
                }
                std::fprintf(stderr, "\n");
            }
        }
#if CSHOGI_ENABLE_DFPN_TRACE_CODE
        const bool trace_fixed_defense = []() {
            static const bool enabled = dfpn_env_flag("CSHOGI_FIXED_DEFENSE_TRACE");
            return enabled;
        }();
        const bool trace_fixed_defense_board_key = trace_board_key_env_enabled() && trace_board_key_from_env(board_index_key(pos));
        const bool trace_fixed_a3_defense = g_trace_fixed_a3_window
            && dfpn_observe_env_flag("CSHOGI_DFPN_ZUKOU_FIXED_A3_DEFENSE")
            && last_attack_move
            && last_attack_move.toUSI() == "2f4f";
#else
        constexpr bool trace_fixed_defense = false;
        constexpr bool trace_fixed_defense_board_key = false;
        constexpr bool trace_fixed_a3_defense = false;
#endif
        if (trace_fixed_defense || trace_fixed_defense_board_key || trace_fixed_a3_defense) {
            std::fprintf(stderr, "cshogi fixed defense moves nonblock=%d blockable=%d size=%zu",
                nonblock_moves, blockable_check ? 1 : 0, moves.size());
            for (const Move move : moves) {
                std::fprintf(stderr, " %s", move.toUSI().c_str());
            }
            std::fprintf(stderr, " sfen=%s\n", pos.toSFEN().c_str());
        }

        const size_t initial_moves = moves.size();
        if (moves.empty() && !blockable_check) {
            if (last_attack_move && last_attack_move.isDrop() && last_attack_move.pieceTypeDropped() == Pawn) {
                return ProofDisproof::PawnCheckmate();
            }
            if (proof_pieces) {
                *proof_pieces = proof_pieces_leaf(pos, attack_color, pos.hand(attack_color));
            }
            return ProofDisproof::NoEscape();
        }

        if (num_captures > 0 && nonblock_moves > 2) {
            if (nonblock_moves > 3) {
                return ProofDisproof(static_cast<uint32_t>(nonblock_moves + (blockable_check ? 1 : 0)), 1);
            }
        }

        const bool cut_candidate =
            nonblock_moves - ((pos.hand(attack_color).exists<HGold>() || pos.hand(attack_color).exists<HSilver>()) ? 1 : 0) > 4;
        if (cut_candidate) {
            return ProofDisproof(static_cast<uint32_t>(nonblock_moves), 1);
        }

        uint32_t min_disproof = ProofDisproof::DISPROOF_MAX;
        uint32_t sum_proof = 0;
        Hand aggregate = zero_hand();
        size_t move_index = 0;
        bool added_blocking_moves = false;
        size_t no_promote_moves = 0;
        while (true) {
            while (move_index < moves.size()) {
                const Move move = moves[move_index++];
                StateInfo st;
                pos.doMove(move, st);

                Move child_best = Move::moveNone();
                Hand child_proof = zero_hand();
                const ProofDisproof child_pdp = fixed_escape_by_move_zero(
                    pos, attack_color, &child_best, &child_proof,
                    no_proof_pieces_attack_estimation, false, current_piece_numbers);

                pos.undoMove(move);
                if (best_move && child_best) {
                    *best_move = child_best;
                }

                if (child_pdp.disproof < min_disproof) {
                    if (child_pdp.disproof == 0) {
                        return child_pdp;
                    }
                    min_disproof = child_pdp.disproof;
                }
                sum_proof += child_pdp.proof;
                if (sum_proof == 0) {
                    aggregate = hand_max(aggregate, child_proof);
                    if (dfpn_trace_zukou001_isolated_d2_enabled()
                        && pos.toSFEN().find("2k1R4/GNNp5/1S7/8K w ") != std::string::npos
                        && child_proof != zero_hand()) {
                        std::fprintf(stderr,
                            "cshogi zukou001 fixed-has-escape aggregate move=%s child=%u,%u child_best=%s child_proof=[%s] aggregate=[%s] sfen=%s\n",
                            move.toUSI().c_str(),
                            child_pdp.proof,
                            child_pdp.disproof,
                            child_best ? child_best.toUSI().c_str() : "-",
                            hand_debug_string(child_proof).c_str(),
                            hand_debug_string(aggregate).c_str(),
                            pos.toSFEN().c_str());
                    }
                }

                if (trace_fixed_probe) {
                    std::fprintf(stderr,
                        "cshogi issue56 d2 child move=%s child=%u,%u best=%s sum=%u min=%u idx=%zu/%zu\n",
                        move.toUSI().c_str(),
                        child_pdp.proof,
                child_pdp.disproof,
                child_best ? child_best.toUSI().c_str() : "-",
                sum_proof,
                min_disproof,
                move_index,
                moves.size());
                }
                if (trace_fixed_defense || trace_fixed_defense_board_key || trace_fixed_a3_defense) {
                    std::fprintf(stderr,
                        "cshogi fixed defense child i=%zu move=%s pdp=%u,%u best=%s proof=[%s] sum=%u min=%u sfen=%s\n",
                        move_index - 1,
                        move.toUSI().c_str(),
                        child_pdp.proof,
                        child_pdp.disproof,
                        child_best ? child_best.toUSI().c_str() : "-",
                        hand_debug_string(child_proof).c_str(),
                        sum_proof,
                        min_disproof,
                        pos.toSFEN().c_str());
                }

                if (sum_proof != 0) {
                    if (move_index < moves.size()) {
                        min_disproof = 1;
                        if (static_cast<int>(move_index - 1) < nonblock_moves) {
                            sum_proof += static_cast<uint32_t>(nonblock_moves - static_cast<int>(move_index));
                        }
                        if (blockable_check) {
                            ++sum_proof;
                        }
                    }
                    if (trace_fixed_probe) {
                        std::fprintf(stderr, "cshogi issue56 d2 return move-first pdp=%u,%u\n", sum_proof, min_disproof);
                    }
                    if (proof_pieces) {
                        *proof_pieces = aggregate;
                    }
                    return ProofDisproof(sum_proof, min_disproof);
                }
            }

            if (sum_proof == 0) {
                if (!added_blocking_moves && blockable_check && moves.size() == initial_moves) {
                    added_blocking_moves = true;
                    collect_raw_blocking_moves();
                    for (const Move move : raw_blocking_moves) {
                        moves.push_back(move);
                    }
                    if (static_cast<int>(moves.size()) > nonblock_moves) {
                        if (trace_fixed_probe) {
                            std::fprintf(stderr, "cshogi issue56 d2 append-blocking");
                            for (size_t i = initial_moves; i < moves.size(); ++i) {
                                std::fprintf(stderr, " %s", moves[i].toUSI().c_str());
                            }
                            std::fprintf(stderr, "\n");
                        }
                        if (trace_fixed_defense || trace_fixed_defense_board_key || trace_fixed_a3_defense) {
                            std::fprintf(stderr, "cshogi fixed defense append-blocking");
                            for (size_t i = initial_moves; i < moves.size(); ++i) {
                                std::fprintf(stderr, " %s", moves[i].toUSI().c_str());
                            }
                            std::fprintf(stderr, " sfen=%s\n", pos.toSFEN().c_str());
                        }
                        continue;
                    }
                    if (moves.empty()) {
                        if (proof_pieces) {
                            *proof_pieces = proof_pieces_leaf(pos, attack_color, pos.hand(attack_color));
                        }
                        return ProofDisproof::NoEscape();
                    }
                }

                if (no_promote_moves == 0) {
                    no_promote_moves = moves.size();
                    for (size_t i = 0; i < no_promote_moves; ++i) {
                        const Move move = moves[i];
                        if (!has_ignored_unpromote_escape(move, defense_color)) {
                            continue;
                        }
                        moves.push_back(unpromote_counterpart(pos, move));
                    }
                    if (moves.size() > no_promote_moves) {
                        if (trace_fixed_probe) {
                            std::fprintf(stderr, "cshogi issue56 d2 append-unpromote");
                            for (size_t i = no_promote_moves; i < moves.size(); ++i) {
                                std::fprintf(stderr, " %s", moves[i].toUSI().c_str());
                            }
                            std::fprintf(stderr, "\n");
                        }
                        continue;
                    }
                }
            }

            break;
        }

        if (sum_proof == 0) {
            if (proof_pieces) {
                *proof_pieces = aggregate;
                if (blockable_check) {
                    add_monopolized_pieces(pos.hand(attack_color), pos.hand(defense_color), pos.hand(attack_color), *proof_pieces);
                }
                if (dfpn_trace_zukou001_isolated_d2_enabled()
                    && hand_count(*proof_pieces, HBishop) >= 2) {
                    std::fprintf(stderr,
                        "cshogi zukou001 fixed-has-escape final aggregate=[%s] proof=[%s] attack=[%s] defense=[%s] blockable=%d sfen=%s\n",
                        hand_debug_string(aggregate).c_str(),
                        hand_debug_string(*proof_pieces).c_str(),
                        hand_debug_string(pos.hand(attack_color)).c_str(),
                        hand_debug_string(pos.hand(defense_color)).c_str(),
                        blockable_check ? 1 : 0,
                        pos.toSFEN().c_str());
                }
            }
            if (trace_fixed_probe) {
                std::fprintf(stderr, "cshogi issue56 d2 return-all-success pdp=%u,%u\n",
                    sum_proof, min_disproof);
            }
            return ProofDisproof(sum_proof, min_disproof);
        }

        if (trace_fixed_probe) {
            std::fprintf(stderr, "cshogi issue56 d2 return-final pdp=%u,%u\n", sum_proof, min_disproof);
        }
        return ProofDisproof(sum_proof, min_disproof);
    }

    void trace_root_attack_children(const char* phase, const std::vector<Move>& moves, const std::vector<ChildState>& children,
        const size_t next_index = std::numeric_limits<size_t>::max(), const uint64_t solved = 0, const uint64_t dag_moves = 0) {
        if (!dfpn_trace_enabled() && !dfpn_trace_root_children_enabled()
            && !dfpn_trace_root_snapshot_enabled() && !dfpn_trace_root_dump_enabled()) {
            return;
        }
        std::fprintf(stderr, "cshogi attack root %s\n", phase);
        for (size_t i = 0; i < moves.size(); ++i) {
            std::fprintf(stderr, "  %c %zu %s pdp=%u,%u nodes=%u cost=%d solved=%d dag=%d best=%s\n",
                i == next_index ? '*' : ' ',
                i,
                moves[i].toUSI().c_str(),
                children[i].pdp.proof,
                children[i].pdp.disproof,
                children[i].node_count,
                static_cast<int>(children[i].proof_cost),
                (i < 64 && (solved & (1ull << i))) ? 1 : 0,
                (i < 64 && (dag_moves & (1ull << i))) ? 1 : 0,
                children[i].best_reply ? children[i].best_reply.toUSI().c_str() : "-");
        }
    }

    void trace_root_attack_result_children(const uint32_t node_count, const uint32_t node_limit,
        const ProofDisproof result, const Move best_move, const std::vector<Move>& moves,
        const std::vector<ChildState>& children) {
        if (!dfpn_trace_root_result_release_enabled() && !dfpn_trace_root_result_children_release_enabled()) {
            return;
        }
        const uint32_t filter = dfpn_trace_root_attack_child_limit_release();
        if (filter != 0 && filter != node_limit) {
            return;
        }
        std::fprintf(stderr,
            "cshogi root children limit=%u nodes=%u pdp=%u,%u best=%s\n",
            node_limit,
            node_count,
            result.proof,
            result.disproof,
            best_move ? best_move.toUSI().c_str() : "-");
        for (size_t i = 0; i < moves.size(); ++i) {
            std::fprintf(stderr,
                "  %zu %s pdp=%u,%u nodes=%u best=%s\n",
                i,
                moves[i].toUSI().c_str(),
                children[i].pdp.proof,
                children[i].pdp.disproof,
                children[i].node_count,
                children[i].best_reply ? children[i].best_reply.toUSI().c_str() : "-");
        }
    }

    void trace_root_limits_only_result(const uint32_t node_count, const uint32_t node_limit,
        const ProofDisproof record_pdp, const Move best_move, const uint64_t solved,
        const uint64_t dag_moves, const uint8_t need_full_width, const bool false_branch,
        const std::vector<Move>& moves, const std::vector<ChildState>& children) {
        if (!dfpn_trace_root_limits_only_enabled()) {
            return;
        }
        const uint32_t filter = dfpn_trace_root_limits_filter();
        if (filter != 0 && filter != node_limit) {
            return;
        }
        std::fprintf(stderr,
            "cshogi root limits-only limit=%u nodes=%u pdp=%u,%u best=%s solved=%llu dag=%llu full=%u false=%u\n",
            node_limit,
            node_count,
            record_pdp.proof,
            record_pdp.disproof,
            best_move ? best_move.toUSI().c_str() : "-",
            static_cast<unsigned long long>(solved),
            static_cast<unsigned long long>(dag_moves),
            static_cast<unsigned>(need_full_width),
            false_branch ? 1u : 0u);
        for (size_t i = 0; i < moves.size(); ++i) {
            std::fprintf(stderr,
                "  %zu %s pdp=%u,%u nodes=%u best=%s solved=%d dag=%d full=%u false=%u\n",
                i,
                moves[i].toUSI().c_str(),
                children[i].pdp.proof,
                children[i].pdp.disproof,
                children[i].node_count,
                children[i].best_reply ? children[i].best_reply.toUSI().c_str() : "-",
                (i < 64 && (solved & (1ull << i))) ? 1 : 0,
                (i < 64 && (dag_moves & (1ull << i))) ? 1 : 0,
                static_cast<unsigned>(children[i].need_full_width),
                children[i].false_branch ? 1u : 0u);
        }
    }

    void trace_root_attack_meta(const char* phase, const uint32_t node_count, const uint32_t node_limit) {
        if (!dfpn_trace_enabled() && !dfpn_trace_root_children_enabled()
            && !dfpn_trace_root_snapshot_enabled() && !dfpn_trace_root_dump_enabled()) {
            return;
        }
        std::fprintf(stderr, "cshogi attack root %s meta nodes=%u limit=%u\n", phase, node_count, node_limit);
    }

    void trace_root_defense_children(const char* phase, const std::vector<Move>& history, const std::vector<Move>& moves,
        const std::vector<ChildState>& children, const Threshold& threshold,
        const ProofDisproof record_pdp, const Move record_best, const uint32_t record_node_count,
        const uint8_t record_need_full_width, const uint64_t record_solved, const uint64_t record_dag_moves,
        const uint32_t node_count, const uint32_t node_limit,
        const size_t next_index = std::numeric_limits<size_t>::max()) {
        if ((!dfpn_trace_enabled() && !dfpn_trace_root_summary_enabled()
            && !dfpn_trace_root_children_enabled() && !dfpn_trace_root_result_children_enabled()
            && !dfpn_trace_root_snapshot_enabled()
            && !dfpn_trace_root_children_only_enabled()) || history.size() > 1) {
            return;
        }
        if (dfpn_trace_root_summary_enabled()
            && (history.size() != 1 || history.back().toUSI() != "S*5d")) {
            return;
        }
        const std::string attack_label = history.empty() ? std::string("<root>") : history.back().toUSI();
        std::fprintf(stderr,
            "cshogi defense root %s attack=%s threshold=%u,%u record=%u,%u best=%s nodes=%u need_full=%u node_count=%u limit=%u\n",
            phase,
            attack_label.c_str(),
            threshold.proof,
            threshold.disproof,
            record_pdp.proof,
            record_pdp.disproof,
            record_best ? record_best.toUSI().c_str() : "-",
            record_node_count,
            static_cast<unsigned>(record_need_full_width),
            node_count,
            node_limit);
        for (size_t i = 0; i < moves.size(); ++i) {
            std::fprintf(stderr, "  %c %zu %s pdp=%u,%u nodes=%u best=%s path=%d solved=%d dag=%d full=%u false=%u\n",
                i == next_index ? '*' : ' ',
                i,
                moves[i].toUSI().c_str(),
                children[i].pdp.proof,
                children[i].pdp.disproof,
                children[i].node_count,
                children[i].best_reply ? children[i].best_reply.toUSI().c_str() : "-",
                children[i].path_record ? 1 : 0,
                (i < 64 && (record_solved & (1ull << i))) ? 1 : 0,
                (i < 64 && (record_dag_moves & (1ull << i))) ? 1 : 0,
                static_cast<unsigned>(children[i].need_full_width),
                children[i].false_branch ? 1u : 0u);
        }
    }

