    std::string history_to_usi_string(const std::vector<Move>& history) {
        std::string result;
        for (size_t i = 0; i < history.size(); ++i) {
            if (i != 0) {
                result.push_back(' ');
            }
            result += history[i].toUSI();
        }
        return result;
    }

