        const std::string sfen = pos.toSFEN();
        return sfen.rfind("1pG6/Gs+P6/1P7/p1lsS4/1k2R4/n2l4b/1NPp5/1S7/8K w ", 0) == 0
            || sfen.rfind("1pG6/Gs+P6/pP7/n1lsS4/+Bk7/n7b/1N1p5/1S7/8K w ", 0) == 0
            || sfen.rfind("1pG6/Gs+P6/pP7/n1lsS4/1k2R4/n7b/1N+Bp5/1S7/8K w ", 0) == 0
            || sfen.rfind("1pG6/Gs+P6/pP7/n1lsS4/1k4R2/n7b/1N+Bp5/1S7/8K w ", 0) == 0
            || sfen.rfind("1pG6/Gs+P6/pP7/n1lsS4/1k1R5/n2l4b/1N+Bp5/1S7/8K w ", 0) == 0
            || sfen.rfind("2G6/1p+P6/pk+R6/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w ", 0) == 0
            || sfen.rfind("2G6/1p+P6/pkR6/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w ", 0) == 0
            || sfen.rfind("2G6/1p+P6/pk3R3/n2sS4/1b2l4/+B1lNl4/1N1p5/1S7/8K w ", 0) == 0;
