    void trace_root_defense_meta(const char* phase, const std::vector<Move>& history, const Threshold& threshold,
        const uint32_t node_count, const uint32_t node_limit) {
        if ((!dfpn_trace_enabled() && !dfpn_trace_root_summary_enabled()
            && !dfpn_trace_root_children_enabled() && !dfpn_trace_root_snapshot_enabled()
            && !dfpn_trace_root_children_only_enabled()) || history.size() > 1) {
            return;
        }
        if (dfpn_trace_root_summary_enabled()
            && (history.size() != 1 || history.back().toUSI() != "S*5d")) {
            return;
        }
        const std::string attack_label = history.empty() ? std::string("<root>") : history.back().toUSI();
        std::fprintf(stderr,
            "cshogi defense root %s meta attack=%s threshold=%u,%u nodes=%u limit=%u\n",
            phase,
            attack_label.c_str(),
            threshold.proof,
            threshold.disproof,
            node_count,
            node_limit);
    }

