    void trace_issue56_check_generation_moves(const char* phase, const Position& pos, const std::vector<Move>& moves) {
        if (!dfpn_trace_all_check_generation_enabled()
            && !dfpn_trace_enabled()
            && !dfpn_issue56_target_trace_enabled()
            && !dfpn_trace_root_children_enabled()) {
            return;
        }
        const std::string sfen = pos.toSFEN();
        if (!trace_issue56_check_generation_sfen(sfen)) {
            return;
        }

        std::fprintf(stderr, "cshogi issue56 check generation %s sfen=%s\n", phase, sfen.c_str());
        for (size_t i = 0; i < moves.size(); ++i) {
            std::fprintf(stderr, "  %zu %s\n", i, moves[i].toUSI().c_str());
        }
    }

    void trace_issue56_check_generation_compare(const Position& pos, const std::vector<Move>& legacy_moves,
        const std::vector<Move>& osl_moves) {
        if (!dfpn_trace_all_check_generation_enabled()
            && !dfpn_trace_enabled()
            && !dfpn_issue56_target_trace_enabled()
            && !dfpn_trace_root_children_enabled()) {
            return;
        }
        const std::string sfen = pos.toSFEN();
        if (!trace_issue56_check_generation_sfen(sfen)) {
            return;
        }

        static bool dumped_compare = false;
        if (dumped_compare) {
            return;
        }
        dumped_compare = true;

        std::vector<u32> legacy_set;
        legacy_set.reserve(legacy_moves.size());
        for (const Move move : legacy_moves) {
            legacy_set.push_back(move.value());
        }
        std::sort(legacy_set.begin(), legacy_set.end());

        std::vector<u32> osl_set;
        osl_set.reserve(osl_moves.size());
        for (const Move move : osl_moves) {
            osl_set.push_back(move.value());
        }
        std::sort(osl_set.begin(), osl_set.end());

        std::fprintf(stderr, "cshogi issue56 check generation compare same_set=%d same_order=%d legacy=%zu osl=%zu\n",
            legacy_set == osl_set ? 1 : 0,
            legacy_moves == osl_moves ? 1 : 0,
            legacy_moves.size(),
            osl_moves.size());
        if (legacy_moves != osl_moves) {
            std::fprintf(stderr, "  legacy order:");
            for (const Move move : legacy_moves) {
                std::fprintf(stderr, " %s", move.toUSI().c_str());
            }
            std::fprintf(stderr, "\n");
            std::fprintf(stderr, "  osl order:");
            for (const Move move : osl_moves) {
                std::fprintf(stderr, " %s", move.toUSI().c_str());
            }
            std::fprintf(stderr, "\n");
        }
    }

