    const auto trace_zukou001_attack_children = [&](const char* phase,
        const size_t next_index = std::numeric_limits<size_t>::max(),
        const Threshold* child_threshold = nullptr) {
        if (!trace_zukou001_attack && !trace_zukou001_pvcheck_detail) {
            return;
        }
        std::fprintf(stderr, "cshogi zukou001 attack %s history=", phase);
        trace_history_prefix(ctx.move_history);
        std::fprintf(stderr, " threshold=%u,%u", threshold.proof, threshold.disproof);
        if (std::strcmp(phase, "final") == 0 && next_index != std::numeric_limits<size_t>::max()) {
            uint32_t min_proof = ProofDisproof::PROOF_MAX;
            uint32_t second_proof = ProofDisproof::PROOF_MAX;
            uint64_t sum_disproof = 0;
            for (size_t i = 0; i < moves.size(); ++i) {
                if (exact_record.solved & child_bit(i)) {
                    continue;
                }
                uint32_t proof = children[i].pdp.proof;
                const uint32_t disproof = children[i].pdp.disproof;
                if (proof != 0 && disproof != 0) {
                    proof = saturate_sum(static_cast<uint64_t>(proof) + children[i].proof_cost, ProofDisproof::PROOF_MAX);
                }
                if (proof < min_proof
                    || (proof == min_proof
                        && disproof != 0
                        && (i == next_index || disproof < children[next_index].pdp.disproof))) {
                    second_proof = min_proof;
                    min_proof = proof;
                }
                else if (proof < second_proof) {
                    second_proof = proof;
                }
                sum_disproof += disproof;
            }
            std::fprintf(stderr,
                " nodes=%u limit=%u min=%u second=%u sum=%llu next=%s",
                ctx.node_count,
                ctx.node_limit,
                min_proof,
                second_proof,
                static_cast<unsigned long long>(sum_disproof),
                next_index < moves.size() ? moves[next_index].toUSI().c_str() : "-");
        }
        if (child_threshold) {
            std::fprintf(stderr, " child_threshold=%u,%u", child_threshold->proof, child_threshold->disproof);
        }
        std::fprintf(stderr, "\n");
        for (size_t i = 0; i < moves.size(); ++i) {
            StateInfo trace_state;
            pos.doMove(moves[i], trace_state);
            const Key trace_child_key = board_index_key(pos);
            pos.undoMove(moves[i]);
            std::fprintf(stderr,
                "  %c %zu %s usi=%s key=%llu pdp=%u,%u nodes=%u cost=%d best=%s path=%d num=%d\n",
                i == next_index ? '*' : ' ',
                i,
                moves[i].toUSI().c_str(),
                moves[i].toUSI().c_str(),
                static_cast<unsigned long long>(trace_child_key),
                children[i].pdp.proof,
                children[i].pdp.disproof,
                children[i].node_count,
                static_cast<int>(children[i].proof_cost),
                children[i].best_reply ? children[i].best_reply.toUSI().c_str() : "-",
                children[i].path_record ? 1 : 0,
                ctx.piece_numbers ? ctx.piece_numbers->number_of_move_piece(moves[i]) : -2);
        }
    };
