            if (best_move) {
                *best_move = result_best;
            }
            if (ctx.move_history.empty()) {
                trace_root_attack_result_children(ctx.node_count, ctx.node_limit, result, result_best, moves, children);
                trace_root_limits_only_result(ctx.node_count, ctx.node_limit,
                    exact_record.proof_disproof, result_best, exact_record.solved, exact_record.dag_moves,
                    exact_record.need_full_width, exact_record.false_branch, moves, children);
            }
